# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from eth_account.messages import encode_defunct
from web3 import Web3

app = Flask(__name__)
w3 = Web3(Web3.HTTPProvider('http://127.0.0.1:8545'))  # Use the appropriate Ethereum node address 

@app.route("/auth", methods=['POST'])
def auth():
    content = request.get_json()

    msg = content['message']
    signature = content['signature']
    address = content['address']

    sign_hash = encode_defunct(text=msg)
    recovered_address = w3.eth.account.recover_message(sign_hash, signature=signature)

    if recovered_address.lower() == address.lower(): 
        return jsonify({"status": "success", "message": "Authentication successful"}), 200
    else:
        return jsonify({"status": "failure", "message": "Authentication failed"}), 401

if __name__ == "__main__":
    app.run(port=5000)